    /** Chart toolbar configuration */
    toolbar?: TimeseriesChartToolbarConfig;
    /** Chart interactions configuration */
    interactions?: ChartInteractionsConfig;
    /** Chart legend properties */
    legend?: TimeseriesChartLegendProps;
    /** Chart X Axis properties */
