    /** Defines the tooltip configuration */
    tooltip: TimeseriesChartTooltipConfig;
    /** Chart interactions configuration */
    interactions: ChartInteractionsConfig;
    /** Chart toolbar configuration */
    toolbar?: TimeseriesToolbarInternalProps;
    /** Chart legend configuration */
    legend: TimeseriesChartLegendConfig;
    /** Chart X Axis configuration */
    xAxis?: TimeseriesChartXAxisConfig;
    /** Chart y-axis configuration */
    yAxis: TimeseriesChartYAxisConfig;
    /** Chart annotations configuration */
    annotations: TimeseriesAnnotationsConfigContextProps | undefined;
    /** Truncation mode applied when the text overflow */
    truncationMode: TruncationMode;
    /** Chart thresholds configuration */
    thresholds?: TimeseriesChartThresholdsConfig;
    /** Defines the curve shape of the area and line series */
    curve?: SeriesCurve;
    /** Enables the infiniteZoom  */
    infiniteZoom: boolean;
    /** Chart selection interaction  */
    select?: TimeseriesSelectProps;
    /** Color rules to apply custom colors to series */
